#include<bits/stdc++.h>
using namespace std;

int main(){
    int n,anns=0;
    cin>>n;
    for(int i=1;i<=n;i++){
        string a;
        int ans=0;
        cin>>a;
        for(int i=0;i<a.size();i++) ans+=(a[i]-'0');
        anns=max(anns,ans);
    } 
    cout<<anns;
    return 0;
}
